这里是简介 题意给定$n​$个矩形$(x_1,y_1,x_2,y_2)​$，求这$n​$个矩形的面积并 题解扫描线裸题，可以不用线段树维护，$O(n^2)$是允许的。 #include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using std::sort; using std::unique; using std::lower_bound; const int N = 1e2 + 10; int n, m, tot; double ans, x1[N], y1[N], x2[N], y2[N], raw[N &lt;&lt; 1], tmp[N &lt;&lt; 1]; struct Node { double x, dy, uy, g; inline bool operator &lt; (const Node &amp;a) const { return x &lt; a.x; } } cy[N &lt;&lt; 1]; int cnt; double val[N &lt;&lt; 3]; int fg[N &lt;&lt; 3]; inline void update(int o, int l, int r) { if(fg[o]) val[o] = raw[r + 1] - raw[l]; else if(l == r) val[o] = 0; else val[o] = val[o &lt;&lt; 1] + val[o &lt;&lt; 1 | 1]; } void modify (int ml, int mr, int k, int o = 1, int l = 1, int r = m) { if(l &gt;= ml &amp;&amp; r &lt;= mr) { fg[o] += k, update(o, l, r); return ; } int mid = (l + r) &gt;&gt; 1, lc = o &lt;&lt; 1, rc = lc | 1; if(ml &lt;= mid) modify(ml, mr, k, lc, l, mid); if(mr &gt; mid) modify(ml, mr, k, rc, mid + 1, r); update(o, l, r); } int main () { while(scanf(&quot;%d&quot;, &amp;n) != EOF) { if(!n) break; ++tot; ans = m = cnt = 0; memset(val, 0, sizeof val), memset(fg, 0, sizeof fg); for(int i = 1; i &lt;= n; ++i) { scanf(&quot;%lf%lf%lf%lf&quot;, x1 + i, y1 + i, x2 + i, y2 + i); tmp[++m] = y1[i], tmp[++m] = y2[i]; } sort(&amp;tmp[1], &amp;tmp[m + 1]); m = unique(&amp;tmp[1], &amp;tmp[m + 1]) - tmp - 1; for(int i = 1; i &lt;= n; ++i) { int ind1 = lower_bound(&amp;tmp[1], &amp;tmp[m + 1], y1[i]) - tmp; int ind2 = lower_bound(&amp;tmp[1], &amp;tmp[m + 1], y2[i]) - tmp; raw[ind1] = y1[i], raw[ind2] = y2[i], y1[i] = ind1, y2[i] = ind2; } for(int i = 1; i &lt;= n; ++i) { cy[++cnt] = (Node){x1[i], y1[i], y2[i], 1}; cy[++cnt] = (Node){x2[i], y1[i], y2[i], -1}; } sort(&amp;cy[1], &amp;cy[cnt + 1]); for(int i = 1; i &lt;= cnt; ++i) { modify(cy[i].dy, cy[i].uy - 1, cy[i].g); ans += val[1] * (cy[i + 1].x - cy[i].x); } printf(&quot;Test case #%d
Total explored area: %.2lf

&quot;, tot, ans); } return 0; }

这里是简介 题意原文很清楚了 题解重链剖分模板题，用线段树维护即可。 #include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using std::max; using std::swap; const int N = 3e4 + 10, Inf = 1e9 + 7; int n, q, c[N], x, y; int fa[N], dep[N], son[N], siz[N]; int top[N], w[N], dfn[N], time; int cnt, from[N], to[N &lt;&lt; 1], nxt[N &lt;&lt; 1];//Edges; int maxv[N &lt;&lt; 2], sumv[N &lt;&lt; 2];//SegTree inline void addEdge(int u, int v) { to[++cnt] = v, nxt[cnt] = from[u], from[u] = cnt; } void dfs1(int u) { siz[u] = 1, dep[u] = dep[fa[u]] + 1; for (int i = from[u]; i; i = nxt[i]) { int v = to[i]; if(v == fa[u]) continue; fa[v] = u, dfs1(v), siz[u] += siz[v]; if(siz[v] &gt; siz[son[u]]) son[u] = v; } } void dfs2(int u, int t) { top[u] = t, dfn[u] = ++time, w[time] = c[u]; if(!son[u]) { return ; } dfs2(son[u], t); for (int i = from[u]; i; i = nxt[i]) { int v = to[i]; if (v != fa[u] &amp;&amp; v != son[u]) dfs2(v, v); } } void pushup (int o, int lc, int rc) { sumv[o] = sumv[lc] + sumv[rc]; maxv[o] = max(maxv[lc], maxv[rc]); } void build(int o = 1, int l = 1, int r = n) { if(l == r) { sumv[o] = maxv[o] = w[l]; return ; } int mid = (l + r) &gt;&gt; 1, lc = o &lt;&lt; 1, rc = lc | 1; build(lc, l, mid), build(rc, mid + 1, r), pushup(o, lc, rc); } void modify(int p, int k, int o = 1, int l = 1, int r = n) { if(l == r &amp;&amp; l == p) { sumv[o] = maxv[o] = k; return ; } int mid = (l + r) &gt;&gt; 1, lc = o &lt;&lt; 1, rc = lc | 1; if(p &lt;= mid) modify(p, k, lc, l, mid); else modify(p, k, rc, mid + 1, r); pushup(o, lc, rc); } int quemax(int ql, int qr, int o = 1, int l = 1, int r = n) { if(l &gt;= ql &amp;&amp; r &lt;= qr) return maxv[o]; int mid = (l + r) &gt;&gt; 1, lc = o &lt;&lt; 1, rc = lc | 1, ret = -Inf; if(ql &lt;= mid) ret = quemax(ql, qr, lc, l, mid); if(qr &gt; mid) ret = max(ret, quemax(ql, qr, rc, mid + 1, r)); return ret; } int quesum(int ql, int qr, int o = 1, int l = 1, int r = n) { if(l &gt;= ql &amp;&amp; r &lt;= qr) return sumv[o]; int mid = (l + r) &gt;&gt; 1, lc = o &lt;&lt; 1, rc = lc | 1, ret = 0; if(ql &lt;= mid) ret = quesum(ql, qr, lc, l, mid); if(qr &gt; mid) ret += quesum(ql, qr, rc, mid + 1, r); return ret; } int quem(int x, int y) { int fx = top[x], fy = top[y], ret = -Inf; while(fx != fy) { if(dep[fx] &gt;= dep[fy]) ret = max(ret, quemax(dfn[fx], dfn[x])), x = fa[fx], fx = top[x]; else ret = max(ret, quemax(dfn[fy], dfn[y])), y = fa[fy], fy = top[y]; } if(dfn[x] &gt; dfn[y]) swap(x, y); return max(ret, quemax(dfn[x], dfn[y])); } int ques(int x, int y) { int fx = top[x], fy = top[y], ret = 0; while(fx != fy) { if(dep[fx] &gt;= dep[fy]) ret += quesum(dfn[fx], dfn[x]), x = fa[fx], fx = top[x]; else ret += quesum(dfn[fy], dfn[y]), y = fa[fy], fy = top[y]; } if(dfn[x] &gt; dfn[y]) swap(x, y); return ret + quesum(dfn[x], dfn[y]); } int main () { scanf(&quot;%d&quot;, &amp;n); for (int i = 1, u, v; i &lt; n; ++i) { scanf(&quot;%d%d&quot;, &amp;u, &amp;v); addEdge(u, v), addEdge(v, u); } for (int i = 1; i &lt;= n; ++i) scanf(&quot;%d&quot;, &amp;c[i]); dfs1(1), dfs2(1, 1); build(); scanf(&quot;%d&quot;, &amp;q); char opt[10]; while(q--) { scanf(&quot;
%s %d %d&quot;, opt, &amp;x, &amp;y); if(opt[0] == 'Q') { if(opt[1] == 'M') printf(&quot;%d
&quot;, quem(x, y)); else printf(&quot;%d
&quot;, ques(x, y)); } else modify(dfn[x], y); } return 0; }

这里是简介 思路简单分析题目可以看出这是一道多重背包题目，不妨将价值看成重量，于是有我们要凑出的重量为：$w= rac{\sum_{i=1}^{6}{w[i]*i}}{2}$但是当前复杂度会超时…所以我们要优化时间复杂度因为当我们做多重背包时，我们是将它转化成01背包来做的（即选1件-N件）所以我们可以采用二进制拆分的方式进行优化： 不妨设当前有7件价值为1的物品。7(10) = 111(2)，将7分成1件，2件和4件选一件+选两件=选三件，以此类推于是就从多重背包变成了裸的01背包！ 代码#include &lt;cstdio&gt; #include &lt;cstring&gt; typedef long long ll; const ll N = 6e4 + 10, M = 2e4 + 10; ll n[7], sum, yq, t, w[M], cnt; bool dp[N]; int main () { while (true) { memset (dp, false, sizeof dp); cnt = 0, sum = 0, ++t; for (register ll i = 1; i &lt;= 6; ++i) { scanf (&quot;%lld&quot;, n + i); sum += n[i] * i; } if (!sum) return 0; //特判，当和为奇数时，显然不能分 if (sum &amp; 1) { printf (&quot;Collection #%lld:
&quot;, t); puts(&quot;Can't be divided.&quot; &quot;
&quot;); continue; } yq = sum &gt;&gt; 1, dp[0] = true; //二进制拆分 for (register ll i = 1; i &lt;= 6; ++i) { ll k = 1, tot = n[i]; while (k &lt;= tot) { w[++cnt] = k * i; tot -= k, k &lt;&lt;= 1; } if (tot) w[++cnt] = tot * i; } //01背包 for (register ll i = 1; i &lt;= cnt; ++i) for (register ll j = yq; j &gt;= w[i]; --j) dp[j] |= dp[j - w[i]]; printf (&quot;Collection #%lld:
&quot;, t); puts (dp[yq] ? &quot;Can be divided.
&quot; : &quot;Can't be divided.
&quot;); } return 0; }
